const rows = $input.all();
const config = rows?.[0]?.json?.value || {};
const today = new Date().toISOString().slice(0, 10);
const isNewDay = (config.last_run_date || null) !== today;
return [{ json: {
  offset: isNewDay ? (config.last_good_offset || 0) : (config.current_offset || 0),
  novos_hoje: isNewDay ? 0 : (config.novos_hoje || 0),
  totalVerificados: isNewDay ? 0 : (config.totalVerificados || 0),
  last_good_offset: config.last_good_offset || 0,
  metaDiaria: 10,
  capVerificados: 500,
  hasMore: true,
  today
}}];

const allItems = $input.all();
const estado = $('Inicializar Estado').first().json;

let apiResponse = null;
const existingIds = new Set();

for (const item of allItems) {
  if (Array.isArray(item.json.items)) apiResponse = item.json;
  else if (item.json.original_id) existingIds.add(item.json.original_id);
}

const currentOffset = estado.offset || 0;
let novos_hoje = estado.novos_hoje || 0;
let totalVerificados = estado.totalVerificados || 0;
const metaDiaria = estado.metaDiaria || 10;
const capVerificados = estado.capVerificados || 500;
const today = estado.today;
const last_good_offset = estado.last_good_offset || 0;

if (!apiResponse) {
  return [{ json: {
    _tem_novos: false,
    _meta: { hasMore: false, nextOffset: currentOffset + 100, novos_hoje, totalVerificados, metaDiaria, capVerificados, today, last_good_offset }
  }}];
}

const items = apiResponse.items || [];
const hasMore = apiResponse.hasMore || false;
totalVerificados += items.length;

const candidatos = items.filter(i => !i.isPremium && i.prompt && i.prompt.trim() !== '');
const ineditos = candidatos.filter(i => !existingIds.has(i.id));
const aProcessar = ineditos.slice(0, Math.max(0, metaDiaria - novos_hoje));
const novoLastGoodOffset = aProcessar.length > 0 ? currentOffset : last_good_offset;

const meta = {
  hasMore,
  nextOffset: currentOffset + 100,
  novos_hoje: novos_hoje + aProcessar.length,
  totalVerificados,
  metaDiaria,
  capVerificados,
  today,
  last_good_offset: novoLastGoodOffset
};

if (aProcessar.length === 0) {
  return [{ json: { _tem_novos: false, _meta: meta } }];
}

const resultado = aProcessar.map(item => ({
  json: {
    _tem_novos: true,
    original_id: item.id,
    title: item.title,
    full_prompt: item.prompt,
    image_url: item.image || null,
    author_name: item.creatorName || null,
    tags: item.tags || [],
    source_url: `https://www.bananaprompts.xyz/prompts/${item.id}`,
    model_name: item.model || null,
    _meta: meta
  }
}));

return resultado;

const items = $input.all();
let meta = null;
for (const item of items) {
  if (item.json._meta) { meta = item.json._meta; break; }
}
if (!meta) {
  return [{ json: {
    continue: false,
    motivo: 'sem_meta',
    _save_state: { offset: 0, novos_hoje: 0, totalVerificados: 0, last_good_offset: 0, last_run_date: null, current_offset: 0 }
  }}];
}
const { novos_hoje, totalVerificados, metaDiaria, capVerificados, hasMore, nextOffset, today, last_good_offset } = meta;
const metaAtingida = novos_hoje >= metaDiaria;
const capEstourado = totalVerificados >= capVerificados;
const deveContinuar = !metaAtingida && !capEstourado && hasMore;
let motivo = 'continuando';
if (metaAtingida) motivo = `meta_atingida (${novos_hoje}/${metaDiaria})`;
else if (capEstourado) motivo = `cap_atingido (${totalVerificados})`;
else if (!hasMore) motivo = 'sem_mais_paginas';
return [{ json: {
  continue: deveContinuar,
  motivo,
  offset: nextOffset,
  novos_hoje,
  totalVerificados,
  last_good_offset,
  metaDiaria,
  capVerificados,
  hasMore,
  today,
  _save_state: {
    offset: nextOffset,
    novos_hoje,
    totalVerificados,
    last_good_offset,
    last_run_date: today,
    current_offset: deveContinuar ? nextOffset : 0
  }
}}];
